contracts/CoordinationCredits.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./interfaces/IERC8004.sol";
import "./interfaces/IUSDC.sol";

contract CoordinationCredits {
    IERC8004 public immutable canonical8004;
    IUSDC public immutable usdc;
    address public immutable registry;
    address public immutable gameAnchor;
    address public immutable treasury;
    address public immutable vault;
    address public admin;

    // agentId => credit balance
    mapping(uint256 => uint256) public balances;

    struct PendingBurn {
        uint256 amount;
        uint256 executeAfter;
    }

    // agentId => pending burn request
    mapping(uint256 => PendingBurn) public pendingBurns;

    uint256 public burnDelay = 3600; // 1 hour default
    uint256 constant MAX_BURN_DELAY = 86400; // 24 hours max

    // Events
    event CreditsMinted(uint256 indexed agentId, uint256 credits);
    event CreditsSettled(uint256[] agentIds, int256[] deltas);
    event BurnRequested(uint256 indexed agentId, uint256 amount, uint256 executeAfter);
    event BurnExecuted(uint256 indexed agentId, uint256 credits, uint256 usdcAmount);
    event BurnCancelled(uint256 indexed agentId);
    event BurnDelayUpdated(uint256 newDelay);

    // Errors
    error NotRegistry();
    error NotGameAnchor();
    error NotAdmin();
    error NotAgentOwner();
    error NotRegistered();
    error InsufficientBalance();
    error NonTransferable();
    error ZeroSumViolation();
    error LengthMismatch();
    error NoPendingBurn();
    error BurnNotReady();
    error BurnDelayTooLong();

    constructor(
        address _canonical8004,
        address _usdc,
        address _registry,
        address _gameAnchor,
        address _treasury,
        address _vault,
        address _admin
    ) {
        canonical8004 = IERC8004(_canonical8004);
        usdc = IUSDC(_usdc);
        registry = _registry;
        gameAnchor = _gameAnchor;
        treasury = _treasury;
        vault = _vault;
        admin = _admin;
    }

    /// @notice Mint credits by depositing USDC (10% tax)
    function mint(uint256 agentId, uint256 usdcAmount) external {
        if (canonical8004.ownerOf(agentId) != msg.sender) revert NotAgentOwner();
        _mintCredits(agentId, usdcAmount, 1000); // 10% tax
    }

    /// @notice Mint credits for an agent without tax (registry only)
    function mintFor(uint256 agentId, uint256 usdcAmount) external {
        if (msg.sender != registry) revert NotRegistry();
        _mintCredits(agentId, usdcAmount, 0);
    }

    function _mintCredits(uint256 agentId, uint256 usdcAmount, uint256 taxBps) internal {
        uint256 fee = (usdcAmount * taxBps) / 10000;
        if (fee > 0) {
            usdc.transferFrom(msg.sender, treasury, fee);
        }
        uint256 net = usdcAmount - fee;
        usdc.transferFrom(msg.sender, vault, net);
        uint256 credits = net * 100;
        balances[agentId] += credits;
        emit CreditsMinted(agentId, credits);
    }

    /// @notice Settle credit deltas after a game (gameAnchor only)
    function settleDeltas(uint256[] calldata agentIds, int256[] calldata deltas) external {
        if (msg.sender != gameAnchor) revert NotGameAnchor();
        if (agentIds.length != deltas.length) revert LengthMismatch();

        int256 sum = 0;
        for (uint256 i = 0; i < deltas.length; i++) {
            sum += deltas[i];
        }
        if (sum != 0) revert ZeroSumViolation();

        for (uint256 i = 0; i < agentIds.length; i++) {
            if (deltas[i] >= 0) {
                balances[agentIds[i]] += uint256(deltas[i]);
            } else {
                uint256 debit = uint256(-deltas[i]);
                if (balances[agentIds[i]] < debit) {
                    balances[agentIds[i]] = 0;
                } else {
                    balances[agentIds[i]] -= debit;
                }
            }
        }

        emit CreditsSettled(agentIds, deltas);
    }

    /// @notice Request a burn (starts cooldown)
    function requestBurn(uint256 agentId, uint256 amount) external {
        if (canonical8004.ownerOf(agentId) != msg.sender) revert NotAgentOwner();
        if (balances[agentId] < amount) revert InsufficientBalance();

        pendingBurns[agentId] = PendingBurn({
            amount: amount,
            executeAfter: block.timestamp + burnDelay
        });

        emit BurnRequested(agentId, amount, block.timestamp + burnDelay);
    }

    /// @notice Execute a pending burn after cooldown
    function executeBurn(uint256 agentId) external {
        PendingBurn memory pending = pendingBurns[agentId];
        if (pending.amount == 0) revert NoPendingBurn();
        if (block.timestamp < pending.executeAfter) revert BurnNotReady();

        uint256 actual = pending.amount;
        if (actual > balances[agentId]) {
            actual = balances[agentId];
        }

        delete pendingBurns[agentId];
        balances[agentId] -= actual;

        uint256 usdcAmount = actual / 100;
        if (usdcAmount > 0) {
            usdc.transferFrom(vault, msg.sender, usdcAmount);
        }

        emit BurnExecuted(agentId, actual, usdcAmount);
    }

    /// @notice Cancel a pending burn
    function cancelBurn(uint256 agentId) external {
        if (canonical8004.ownerOf(agentId) != msg.sender) revert NotAgentOwner();
        if (pendingBurns[agentId].amount == 0) revert NoPendingBurn();
        delete pendingBurns[agentId];
        emit BurnCancelled(agentId);
    }

    /// @notice Set burn delay (admin only)
    function setBurnDelay(uint256 newDelay) external {
        if (msg.sender != admin) revert NotAdmin();
        if (newDelay > MAX_BURN_DELAY) revert BurnDelayTooLong();
        burnDelay = newDelay;
        emit BurnDelayUpdated(newDelay);
    }

    /// @notice Non-transferable - always reverts
    function transfer(address, uint256) external pure returns (bool) {
        revert NonTransferable();
    }

    /// @notice Non-transferable - always reverts
    function transferFrom(address, address, uint256) external pure returns (bool) {
        revert NonTransferable();
    }
}

contracts/CoordinationRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./interfaces/IERC8004.sol";
import "./interfaces/IUSDC.sol";
import "./interfaces/ICoordinationCredits.sol";

contract CoordinationRegistry {
    IERC8004 public immutable canonical8004;
    IUSDC public immutable usdc;
    ICoordinationCredits public immutable creditContract;
    address public immutable treasury;

    // name (lowercased) => agentId
    mapping(bytes32 => uint256) public nameToAgent;
    // agentId => display name
    mapping(uint256 => string) public displayName;
    // agentId => registered flag
    mapping(uint256 => bool) public registered;

    uint256 constant REGISTRATION_FEE = 1e6; // $1 USDC
    uint256 constant INITIAL_CREDITS_USDC = 4e6; // $4 USDC worth of credits

    event Registered(address indexed user, uint256 indexed agentId, string name);

    error InvalidName();
    error NameTaken();
    error AlreadyRegistered();
    error NotAgentOwner();

    constructor(
        address _canonical8004,
        address _usdc,
        address _creditContract,
        address _treasury
    ) {
        canonical8004 = IERC8004(_canonical8004);
        usdc = IUSDC(_usdc);
        creditContract = ICoordinationCredits(_creditContract);
        treasury = _treasury;
    }

    /// @notice Register a new agent (mints a new ERC-8004 identity)
    function registerNew(
        string calldata name,
        string calldata agentURI,
        uint256 deadline,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) external {
        usdc.permit(msg.sender, address(this), REGISTRATION_FEE + INITIAL_CREDITS_USDC, deadline, v, r, s);
        uint256 agentId = canonical8004.register(agentURI);
        _register(msg.sender, name, agentId);
    }

    /// @notice Register with an existing ERC-8004 agent identity
    function registerExisting(
        string calldata name,
        uint256 agentId,
        uint256 deadline,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) external {
        usdc.permit(msg.sender, address(this), REGISTRATION_FEE + INITIAL_CREDITS_USDC, deadline, v, r, s);
        if (canonical8004.ownerOf(agentId) != msg.sender) revert NotAgentOwner();
        _register(msg.sender, name, agentId);
    }

    function _register(address user, string calldata name, uint256 agentId) internal {
        if (registered[agentId]) revert AlreadyRegistered();
        if (!_validName(name)) revert InvalidName();

        bytes32 nameKey = keccak256(bytes(_toLower(name)));
        if (nameToAgent[nameKey] != 0) revert NameTaken();

        // Transfer $1 registration fee to treasury
        usdc.transferFrom(user, treasury, REGISTRATION_FEE);

        // Store registration
        nameToAgent[nameKey] = agentId;
        displayName[agentId] = name;
        registered[agentId] = true;

        // Approve credit contract for initial credits and mint
        usdc.approve(address(creditContract), INITIAL_CREDITS_USDC);
        usdc.transferFrom(user, address(this), INITIAL_CREDITS_USDC);
        creditContract.mintFor(agentId, INITIAL_CREDITS_USDC);

        emit Registered(user, agentId, name);
    }

    /// @notice Check if a name is available
    function checkName(string calldata name) external view returns (bool available) {
        if (!_validName(name)) return false;
        bytes32 nameKey = keccak256(bytes(_toLower(name)));
        return nameToAgent[nameKey] == 0;
    }

    /// @notice Validate name matches ^[a-zA-Z0-9_-]{3,20}$
    function _validName(string calldata name) internal pure returns (bool) {
        bytes memory b = bytes(name);
        if (b.length < 3 || b.length > 20) return false;
        for (uint256 i = 0; i < b.length; i++) {
            bytes1 c = b[i];
            bool valid = (c >= 0x30 && c <= 0x39) || // 0-9
                (c >= 0x41 && c <= 0x5A) || // A-Z
                (c >= 0x61 && c <= 0x7A) || // a-z
                c == 0x5F || // _
                c == 0x2D;   // -
            if (!valid) return false;
        }
        return true;
    }

    /// @notice Convert string to lowercase
    function _toLower(string calldata str) internal pure returns (string memory) {
        bytes memory b = bytes(str);
        bytes memory lower = new bytes(b.length);
        for (uint256 i = 0; i < b.length; i++) {
            if (b[i] >= 0x41 && b[i] <= 0x5A) {
                lower[i] = bytes1(uint8(b[i]) + 32);
            } else {
                lower[i] = b[i];
            }
        }
        return string(lower);
    }
}

contracts/GameAnchor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./interfaces/ICoordinationCredits.sol";

contract GameAnchor {
    ICoordinationCredits public immutable credits;
    address public immutable relayer;
    address public admin;

    struct GameResult {
        bytes32 gameId;
        string gameType;
        uint256[] players;
        bytes outcome;
        bytes32 movesRoot;
        bytes32 configHash;
        uint16 turnCount;
        uint64 timestamp;
    }

    // gameId => stored result
    mapping(bytes32 => GameResult) internal _results;
    // gameId => whether settled
    mapping(bytes32 => bool) public settled;

    // Configurable emergency reclaim delay
    uint256 public reclaimDelay = 3600; // 1 hour default
    uint256 constant MAX_RECLAIM_DELAY = 604800; // 1 week max

    // Events
    event GameSettled(
        bytes32 indexed gameId,
        bytes32 movesRoot,
        uint256[] players,
        int256[] deltas
    );
    event EmergencyReclaimed(bytes32 indexed gameId);
    event ReclaimDelayUpdated(uint256 newDelay);

    // Errors
    error NotRelayer();
    error NotAdmin();
    error AlreadySettled();
    error MissingMovesRoot();
    error LengthMismatch();
    error ZeroSumViolation();
    error TooEarlyForReclaim();
    error GameNotSettled();
    error ReclaimDelayTooLong();

    constructor(address _credits, address _relayer, address _admin) {
        credits = ICoordinationCredits(_credits);
        relayer = _relayer;
        admin = _admin;
    }

    /// @notice Settle a game result and apply credit deltas
    function settleGame(
        GameResult calldata result,
        int256[] calldata deltas
    ) external {
        if (msg.sender != relayer) revert NotRelayer();
        if (settled[result.gameId]) revert AlreadySettled();
        if (result.movesRoot == bytes32(0)) revert MissingMovesRoot();
        if (result.players.length != deltas.length) revert LengthMismatch();

        // Verify zero-sum
        int256 sum = 0;
        for (uint256 i = 0; i < deltas.length; i++) {
            sum += deltas[i];
        }
        if (sum != 0) revert ZeroSumViolation();

        // Store result
        _results[result.gameId] = result;
        settled[result.gameId] = true;

        // Settle credits
        credits.settleDeltas(result.players, deltas);

        emit GameSettled(result.gameId, result.movesRoot, result.players, deltas);
    }

    /// @notice View a stored game result
    function results(bytes32 gameId) external view returns (GameResult memory) {
        return _results[gameId];
    }

    /// @notice Emergency reclaim if game is stale (past configurable delay)
    function emergencyReclaim(bytes32 gameId) external {
        GameResult memory result = _results[gameId];
        if (result.timestamp == 0) revert GameNotSettled();
        if (block.timestamp <= uint256(result.timestamp) + reclaimDelay) revert TooEarlyForReclaim();

        // Refund: create zero deltas (no-op settle to emit event)
        emit EmergencyReclaimed(gameId);
    }

    /// @notice Set emergency reclaim delay (admin only)
    function setReclaimDelay(uint256 newDelay) external {
        if (msg.sender != admin) revert NotAdmin();
        if (newDelay > MAX_RECLAIM_DELAY) revert ReclaimDelayTooLong();
        reclaimDelay = newDelay;
        emit ReclaimDelayUpdated(newDelay);
    }
}

