        address owner,
        address spender,
        uint256 value,
        uint256 /* deadline */,
        uint8 /* v */,
        bytes32 /* r */,
        bytes32 /* s */
    ) external {
        // Mock permit — just approve directly
        _approve(owner, spender, value);
    }
}

